using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver (resolves any type)
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1️⃣ GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2️⃣ TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"\nTryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now demonstrate the "not available" path using a source-gen context
// that only knows about Person — asking for int[] will return false.
var limited = new JsonSerializerOptions { TypeInfoResolver = MyContext.Default };

if (limited.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? arrInfo))
{
    Console.WriteLine($"\nTryGetTypeInfo<int[]> succeeded (unexpected)");
}
else
{
    Console.WriteLine($"\nTryGetTypeInfo<int[]> => not available (no throw!)");
}

// Record used in the demo
public record Person(string Name, int Age);

// A source-generated context that only handles Person
[JsonSerializable(typeof(Person))]
public partial class MyContext : JsonSerializerContext;

